# LeafToLife Inventory API Test Script
# Generated by Morpheus

$BASE_URL = "http://localhost:5001/api"
$TOKEN = ""

# Step 1: Get fresh JWT token
try {
    $authResponse = Invoke-WebRequest -Uri "$BASE_URL/auth/login" -Method POST -Headers @{ "Content-Type"="application/json" } -Body '{"email":"superadmin@leaftolife.com.sg","password":"NewPassword123!"}' -UseBasicParsing
    $TOKEN = ($authResponse.Content | ConvertFrom-Json).accessToken
    Write-Host "AUTH: Token acquired OK" -ForegroundColor Green
} catch {
    Write-Host "AUTH FAILED: $_" -ForegroundColor Red
    exit 1
}

$HEADERS = @{
    "Authorization" = "Bearer $TOKEN"
    "Content-Type"  = "application/json"
}

# Results storage
$results = @()

function Test-Endpoint {
    param(
        [string]$Label,
        [string]$Method,
        [string]$Url,
        [string]$Body = $null
    )
    try {
        if ($Body) {
            $resp = Invoke-WebRequest -Uri $Url -Method $Method -Headers $HEADERS -Body $Body -UseBasicParsing -ErrorAction Stop
        } else {
            $resp = Invoke-WebRequest -Uri $Url -Method $Method -Headers $HEADERS -UseBasicParsing -ErrorAction Stop
        }
        $status = $resp.StatusCode
        $pass = if ($status -ge 200 -and $status -lt 300) { "PASS" } else { "FAIL" }
        $notes = ""
        return [PSCustomObject]@{ Endpoint=$Label; Status=$status; Result=$pass; Notes=$notes; Body=$resp.Content }
    } catch {
        $status = 0
        if ($_.Exception.Response) {
            $status = [int]$_.Exception.Response.StatusCode
        }
        return [PSCustomObject]@{ Endpoint=$Label; Status=$status; Result="FAIL"; Notes=$_.Exception.Message.Split("`n")[0]; Body="" }
    }
}

