$passCount = 0
$failCount = 0
$skipCount = 0

foreach ($res in $results) {
    $color = switch ($res.Result) {
        "PASS" { "Green" }
        "FAIL" { "Red" }
        "SKIP" { "Yellow" }
        default { "White" }
    }
    $line = "{0,-42} {1,-6} {2,-6} {3}" -f $res.Endpoint, $res.Status, $res.Result, $res.Notes
    Write-Host $line -ForegroundColor $color

    if ($res.Result -eq "PASS") { $passCount++ }
    elseif ($res.Result -eq "FAIL") { $failCount++ }
    else { $skipCount++ }
}

